# 适用题型：原地旋转矩阵
# 核心思想：顺时针旋转 = 对角线翻转 + 每行翻转
def rotate(matrix):
    n = len(matrix)
    # 1. 从左上到右下，按照对角线元素进行翻转
    for i in range(n):
        for j in range(i+1,n):
            matrix[i][j],matrix[j][i] = matrix[j][i], matrix[i][j]

    # 2. 每行内部对元素进行翻转
    for row in matrix:
        row.reverse()

# 核心思想：逆时针旋转 = 按对角线翻转 + 按列翻转
def rotate_counter_clockwise(matrix):
    n = len(matrix)
    # 1. 按照对角线翻转
    for i in range(n):
        for j in range(i+1,n):
            matrix[i][j], matrix[j][i] =matrix[j][i],matrix[i][j]

    # 2.把列内部元素做翻转（reverse行的顺序即可）
    matrix.reverse()

def spiralOrder(matrix):
    m, n = len(matrix), len(matrix[0]) # m 行， n列
    top, bottom = 0, m-1
    left, right = 0, n-1
    result = []
    while len(result) < m * n:
        # 1. 沿top行（从左往右行进）
        if top <= bottom:
            for j in range(left,right+1):
                result.append(matrix[top][j])
            # top 行更新（上边界往下压缩）
            top += 1

        # 2. 沿right列（从上往下行进）
        if left <= right:
            for j in range(top,bottom+1):
                result.append(matrix[j][right])
            right -= 1 # 右边界收缩

        # 3. 沿bottom行（从右往左）
        if top <= bottom:
            for j in range(right,left-1,-1):
                result.append(matrix[bottom][j])
            # bottom 更新
            bottom -= 1

        # 4. 沿left列（从下往上）
        if left <= right:
            for j in range(bottom,top+1,-1):
                result.append(matrix[j][left])
            left += 1

    return result

def find_duplicate(nums):
    seen = set()
    for x in nums:
        if x in seen():
            return True
        else:
            seen.add(x)
    return False

# 适用于找两个元素之间的相互关系（两数和=target；两数差=target....)
def find_pair(nums,target):
    seen = {} # key:val = 数值:idx
    for i,x in enumerate(nums):
        complement = target - x
        if complement in seen:
            return [seen[complement],i]
        else:
            seen[x] = i
    return []

def count_freq(nums):
    count = {} #val: occurred time
    for x in nums:
        count[x] = count.get(x, 0) + 1
    return count

