from collections import deque

def levelOrder(root):
    if root is None:
        return
    queue = deque([root])

    while queue:
        sz = len(queue)
        for _ in range(sz):
            cur = queue.popleft()
            # process cur node

            for child in cur.children:
                queue.append(child)

